async def seed_database(engine: AsyncEngine) -> None:
    """Check if companies data exists in DB. If not, insert all seed data via SQLAlchemy."""
    session_maker = async_sessionmaker(
        engine, class_=AsyncSession, expire_on_commit=False
    )

    async with session_maker() as session:
        # Check if companies table already has data
        result = await session.execute(
            select(func.count()).select_from(Company)
        )
        count = result.scalar()

        if count and count > 0:
            msg = f"Database already seeded ({count} companies found). Skipping."
            logger.info(msg)
            print(msg)
            return

        logger.info("No companies found in DB. Seeding database...")
        print("No companies found in DB. Seeding database...")

        try:
            # Insert in dependency order: Sectors -> Industries -> Companies -> Listings -> Results

            # 1. Sectors
            sector_objects = [Sector(**s) for s in SECTORS_DATA]
            session.add_all(sector_objects)
            await session.flush()
            logger.info(f"Inserted {len(SECTORS_DATA)} sectors.")

            # 2. Industries
            industry_objects = [Industry(**i) for i in INDUSTRIES_DATA]
            session.add_all(industry_objects)
            await session.flush()
            logger.info(f"Inserted {len(INDUSTRIES_DATA)} industries.")

            # 3. Companies
            company_objects = [Company(**c) for c in COMPANIES_DATA]
            session.add_all(company_objects)
            await session.flush()
            logger.info(f"Inserted {len(COMPANIES_DATA)} companies.")

            # 4. Exchange Listings
            listing_objects = [
                ExchangeListing(**el) for el in EXCHANGE_LISTINGS_DATA
            ]
            session.add_all(listing_objects)
            await session.flush()
            logger.info(
                f"Inserted {len(EXCHANGE_LISTINGS_DATA)} exchange listings."
            )

            # 5. Quarterly Results - convert string dates to date objects and numeric strings to Decimal
            qr_objects = []
            for qr in QUARTERLY_RESULTS_DATA:
                parts = qr["period_end_date"].split("-")
                qr_copy = {
                    "result_id": qr["result_id"],
                    "company_id": qr["company_id"],
                    "quarter": qr["quarter"],
                    "period_end_date": date(
                        int(parts[0]), int(parts[1]), int(parts[2])
                    ),
                    "revenue": Decimal(str(qr["revenue"])),
                    "operating_expenses": Decimal(
                        str(qr["operating_expenses"])
                    ),
                    "operating_profit": Decimal(str(qr["operating_profit"])),
                    "depreciation": Decimal(str(qr["depreciation"])),
                    "interest": Decimal(str(qr["interest"])),
                    "profit_before_tax": Decimal(str(qr["profit_before_tax"])),
                    "tax": Decimal(str(qr["tax"])),
                    "net_profit": Decimal(str(qr["net_profit"])),
                    "eps": Decimal(str(qr["eps"])),
                }
                qr_objects.append(QuarterlyResult(**qr_copy))
            session.add_all(qr_objects)
            await session.flush()
            logger.info(
                f"Inserted {len(QUARTERLY_RESULTS_DATA)} quarterly results."
            )

            await session.commit()
            logger.info("Database seeding completed successfully!")
            print("Database seeding completed successfully!")

        except Exception as e:
            await session.rollback()
            logger.error(f"Error seeding database: {e}")
            print(f"ERROR seeding database: {e}")
            raise
